import { Pipe, PipeTransform, ChangeDetectorRef } from '@angular/core';
import { CustomerService } from '../services/customer.service';
import { Customer } from '../models/customer';

@Pipe({
  name: 'invoiceCustomerPipe',
  standalone: true
})
export class InvoiceCustomerPipe implements PipeTransform {

  public customers: Customer[] = [];
  constructor(
    private readonly customerService: CustomerService,
    private readonly changeDetectorRef: ChangeDetectorRef) {
    this.loadCustomers();
  }

  loadCustomers() {
    this.customerService.getAll()
      .subscribe((data) => {
        this.customers = data;

        this.changeDetectorRef.detectChanges();
      });
  }

  transform(value: number, ...args: unknown[]): string {

    console.log("Pipe..." + value);
    const customer = this.customers.find(x => x.id == value);
    if (customer) {
      console.log("Pipe 2..." + customer.name);
      return customer.name;
    }

    console.log("Pipe 3..." + this.customers.length);
    return "";
  }

}
